mapper.update:
update ${tableName}


        ${key}=#{value}


where id=#{id}

mapper.select:
select * from customer_products
where customer_username=#{customerUsername}
  and code=#{code}
order by id
limit 1

select * from customer_products
where customer_username=#{customerUsername}
  and ifnull(spec_model, '')=#{specModel}
  and ifnull(common_model, '')=#{commonModel}
order by id
limit 1

select * from supplier_quotes
where supplier_username=#{supplierUsername}
  and pricing_group=#{orderNo}
order by id

select * from customer_order_items
where order_no=#{orderNo} and customer_username=#{customerUsername}
order by id

select * from customer_products
where customer_username=#{customerUsername}
order by id asc

select count(*) from customer_order_items
where code=#{code}
  and (status is null or status not in ('CANCELLED','COMPLETED','QUOTE_COMPLETED'))

mapper.update:
update customer_order_items
set pricing_group=#{pricingGroup}, updated_at=current_timestamp
where id=#{id}

update customer_orders
set status='COMPLETED', updated_at=current_timestamp
where order_no=#{orderNo}
  and status!='CANCELLED'
  and exists (
      select 1 from customer_order_items
      where order_no=#{orderNo}
        and (status is null or status!='CANCELLED')
  )
  and not exists (
      select 1 from customer_order_items
      where order_no=#{orderNo}
        and (status is null or status!='CANCELLED')
        and sale_price is null
  )

update supplier_quotes
set pricing_status='USED_PRICE', updated_at=current_timestamp
where id=#{id}

update supplier_quotes
set pricing_status='NOT_USE_PRICE', updated_at=current_timestamp
where id!=#{id}
  and code=#{code}
  and pricing_group=#{pricingGroup}

update supplier_submissions
set code=#{code},new_code=#{newCode},master_product_id=#{masterProductId},status='APPROVED',updated_at=current_timestamp
where id=#{id}

update unmatched_customer_items
set code=#{code},new_code=#{newCode},master_product_id=#{masterProductId},status='APPROVED',updated_at=current_timestamp
where id=#{id}

update customer_products
set code=#{code},new_code=#{newCode},master_product_id=#{masterProductId},matched=true,status='APPROVED',updated_at=current_timestamp
where id=#{id}

update supplier_quotes
purchase_price=#{purchasePrice}, sale_price=#{salePrice}, price_valid_until=#{priceValidUntil}, status=#{status}, updated_at=current_timestamp
where id=#{id}

update supplier_submissions
set purchase_price=#{purchasePrice},
    price_valid_until=#{priceValidUntil},
    updated_at=current_timestamp
where supplier_username=#{supplierUsername}
  and code=#{code}

update customer_order_items
purchase_price=#{purchasePrice}, sale_price=#{salePrice}, status=case when #{purchasePrice} is not null and #{salePrice} is not null then 'QUOTE_COMPLETED' else status end, updated_at=current_timestamp
where id=#{customerItemId}

update internal_products
set order_price_5=order_price_4,
    order_price_4=order_price_3,
    order_price_3=order_price_2,
    order_price_2=order_price_1,
    order_price_1=#{entry},
    updated_at=current_timestamp
where code=#{code}
  and ifnull(order_price_1, '')!=#{entry}
  and ifnull(order_price_2, '')!=#{entry}
  and ifnull(order_price_3, '')!=#{entry}
  and ifnull(order_price_4, '')!=#{entry}
  and ifnull(order_price_5, '')!=#{entry}
